import React from "react";
import { useState, useEffect } from "react";
import Modal from "./AddProperty/Modal";

const HostDashboard = () => {
  console.log("Host Dashboard");
  function addProperty() {
    alert("Add Property");
  }
  const [properties, setProperties] = useState([]);
  const [show, setShow] = useState(false);

  useEffect(() => {
    fetch("http://localhost:9000/properties")
      .then((response) => response.json())
      .then((properties) => {
        console.log(properties);
        setProperties(properties);
      })
      .catch((err) => {
        console.log(err.message);
      });
  }, []);

  const mystyle = {
    marginLeft: "300px",
  };

  async function deleteProperty(id) {
    return fetch(`http://localhost:9000/properties/${id}`, {
      method: 'DELETE',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify()
    })
      .then( (data) =>{ 
        console.log("data : ",data);
        return data.json()
      })
   }

   async function editProperty(id) {
    return fetch(`http://localhost:9000/properties/${id}`, {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify()
    })
      .then( (data) =>{ 
        console.log("data : ",data);
        return data.json()
      })
   }

  async function handleDelete (e, id) {
    e.preventDefault()
    console.log(id)
    const response = await deleteProperty(id);
    if (response.token) {
      console.log(response)
      console.log("Delete Success")
    } else {
      console.log(response)
      console.log("Delete Failed")
    }
  };

  async function handleEdit (e, id) {
    e.preventDefault()
    console.log(id)
    const response = await editProperty(id);
    if (response.token) {
      console.log(response)
      console.log("Delete Success")
    } else {
      console.log(response)
      console.log("Delete Failed")
    }
  };

  return (
    <>
      <h1>Host</h1>
      <button style={mystyle} type="button" className="btn-primary" onClick={() => setShow(true)}>Add a new Property</button>
      <Modal scrollable={true} title="Add New Property" onClose={() => setShow(false)} show={show}>
      </Modal>
      <div className="container" style={{ marginTop: "5%" }}>
        <div className="row">
          <div className="col-12">
            <table className="table table-bordered">
              <thead>
                <tr>
                  <th scope="col">Sr. No.</th>
                  <th scope="col">Title</th>
                </tr>
              </thead>
              <tbody>
                {Object.keys(properties).map((key) => (
                  <tr>
                    <th scope="row">{parseInt(key) + parseInt(1)}</th>
                    <td>{properties[key].title}</td>
                    <td>
                      {/* <button type="button" className="btn btn-primary" onClick={(e) => {handleEdit(e, properties[key]._id);}}>
                        <i className="far" />
                        Edit
                      </button> */}
                      <button style={mystyle} type="button" className="btn-primary" onClick={() => setShow(true)}>Edit</button>
                      <Modal scrollable={true} title="Edit Property" onClose={() => setShow(false)} show={show}>
                      </Modal>
                      <button type="button" className="btn btn-danger"  onClick={(e) => {handleDelete(e, properties[key]._id);}}>
                        <i style={{}} className="far" />
                        Delete
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </>
  );
};

export default HostDashboard;
